import cohere
co = cohere.Client(api_key="your-api-key")

def cohere_rerank(query: str, documents: list[str], top_n: int = 5) -> list[dict]:
    r = co.rerank(query=query, documents=documents, top_n=top_n, model="rerank-english-v3.0")
    return [{"document": documents[res.index], "score": res.relevance_score, "index": res.index}
            for res in r.results]

import requests

def jina_rerank(query: str, documents: list[str], top_n: int = 5, api_key: str = "") -> list[dict]:
    r = requests.post(
        "https://api.jina.ai/v1/rerank",
        headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
        json={"query": query, "documents": documents, "top_n": top_n,
              "model": "jina-reranker-v2-base-multilingual"},
    ).json()
    return [{"document": documents[i["index"]], "score": i["relevance_score"], "index": i["index"]}
            for i in r["results"]]

import voyageai
vo = voyageai.Client(api_key="your-api-key")

def voyage_rerank(query: str, documents: list[str], top_k: int = 5) -> list[dict]:
    r = vo.rerank(query=query, documents=documents, model="rerank-2", top_k=top_k)
    return [{"document": documents[res.index], "score": res.relevance_score, "index": res.index}
            for res in r.results]

import json from openai import OpenAI client = OpenAI()
def llm_rerank(query: str, documents: list[str], top_k: int = 5) -> list[dict]: doc_list = "
".join([f"[{i}] {doc[:500]}" for i, doc in enumerate(documents)]) prompt = (f'Query: {query}

Documents:
{doc_list}

' f'Return JSON: {{"scores": [{{"index": 0, "score": 8}}, ...]}} (0-10 scale).') r = client.chat.completions.create( model="gpt-4o-mini", messages=[{"role": "user", "content": prompt}], response_format={"type": "json_object"}, temperature=0, ) scores = sorted(json.loads(r.choices[0].message.content)["scores"], key=lambda x: x["score"], reverse=True) return [{"document": documents[s["index"]], "score": s["score"] / 10.0, "index": s["index"]} for s in scores[:top_k] if s["index"] < len(documents)]

import logging, time
logger = logging.getLogger(__name__)

def rerank_with_fallback(reranker_fn, query, candidates, top_k=5):
    """candidates: list of str. Returns list of {text, score, index}."""
    try:
        start = time.time()
        results = reranker_fn(query, candidates, top_k)
        logger.info(f"Rerank: {len(candidates)} → {top_k} in {time.time()-start:.3f}s")
        return results
    except Exception as e:
        logger.error(f"Rerank failed ({e}), using original order")
        return [{"text": c, "score": 1.0 - i/len(candidates), "index": i}
                for i, c in enumerate(candidates[:top_k])]
